import{f as p,D as A,o,c as d,a7 as s,b as i,w as r,a as n,G as g,a9 as a,k as e}from"./chunks/framework.DDLK82Pw.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"S6-Go/阶段30-网络与操作系统.md","filePath":"S6-Go/阶段30-网络与操作系统.md","lastUpdated":1780493670000}'),h={name:"S6-Go/阶段30-网络与操作系统.md"};function E(u,t,B,C,q,S){const l=A("Mermaid");return o(),d("div",null,[t[3]||(t[3]=s('<h2 id="🌐-阶段三十-网络与操作系统原理" tabindex="-1">🌐 阶段三十：网络与操作系统原理 <a class="header-anchor" href="#🌐-阶段三十-网络与操作系统原理" aria-label="Permalink to &quot;🌐 阶段三十：网络与操作系统原理&quot;">​</a></h2><h3 id="q291-进程和线程的区别" tabindex="-1">Q291: 进程和线程的区别？ <a class="header-anchor" href="#q291-进程和线程的区别" aria-label="Permalink to &quot;Q291: 进程和线程的区别？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：🔥 高频</p><p><strong>考点</strong>：资源分配、调度单位、隔离级别</p><p><strong>💡 记忆关键词</strong>：资源分配、调度单位、内存隔离</p><p><strong>答案要点</strong>：</p><ul><li><strong>进程</strong>：资源分配的基本单位，独立内存空间</li><li><strong>线程</strong>：CPU 调度的基本单位，共享进程内存</li><li>进程切换开销大，线程切换开销小</li><li>进程间隔离，线程间共享数据需同步</li></ul><hr><h3 id="q292-协程与线程的区别" tabindex="-1">Q292: 协程与线程的区别？ <a class="header-anchor" href="#q292-协程与线程的区别" aria-label="Permalink to &quot;Q292: 协程与线程的区别？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：🔥 高频</p><p><strong>考点</strong>：用户态、栈大小、调度方式</p><p><strong>💡 记忆关键词</strong>：用户态调度、2KB栈、轻量切换</p><p><strong>答案要点</strong>：</p><ul><li><strong>线程</strong>：OS 内核管理，栈 1~2MB，内核态切换</li><li><strong>协程</strong>：用户态管理（如 Go goroutine），栈 2KB 起，用户态切换</li><li>协程切换成本远低于线程</li><li>协程由语言运行时调度，非 OS 调度</li></ul><hr><h3 id="q293-并发和并行有什么区别" tabindex="-1">Q293: 并发和并行有什么区别？ <a class="header-anchor" href="#q293-并发和并行有什么区别" aria-label="Permalink to &quot;Q293: 并发和并行有什么区别？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：时间维度、多核、概念区分</p><p><strong>💡 记忆关键词</strong>：交替执行、同时执行、多核支持</p><p><strong>答案要点</strong>：</p><ul><li><strong>并发</strong>（Concurrency）：多个任务交替执行，宏观同时</li><li><strong>并行</strong>（Parallelism）：多个任务真正同时执行（需多核）</li><li>并发是结构问题，并行是执行问题</li><li>Go 的 goroutine 支持并发，GOMAXPROCS &gt; 1 时支持并行</li></ul><hr><h3 id="q294-进程与线程的切换流程" tabindex="-1">Q294: 进程与线程的切换流程？ <a class="header-anchor" href="#q294-进程与线程的切换流程" aria-label="Permalink to &quot;Q294: 进程与线程的切换流程？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：上下文保存、状态切换、开销</p><p><strong>💡 记忆关键词</strong>：上下文保存、PCB/TCB、页表切换</p><p><strong>答案要点</strong>：</p><ol><li>保存当前进程/线程的上下文（寄存器、PC、SP）</li><li>更新 PCB/TCB 状态</li><li>调度器选择下一个进程/线程</li><li>恢复新进程/线程的上下文</li><li>进程切换需切换页表（TLB 失效），线程切换不需要</li></ol><hr><h3 id="q295-为什么虚拟地址空间切换会比较耗时" tabindex="-1">Q295: 为什么虚拟地址空间切换会比较耗时？ <a class="header-anchor" href="#q295-为什么虚拟地址空间切换会比较耗时" aria-label="Permalink to &quot;Q295: 为什么虚拟地址空间切换会比较耗时？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：TLB 刷新、页表切换、缓存失效</p><p><strong>💡 记忆关键词</strong>：TLB失效、页表切换、缓存命中降</p><p><strong>答案要点</strong>：</p><ul><li>进程切换需切换页表（CR3 寄存器）</li><li>TLB（Translation Lookaside Buffer）缓存失效</li><li>CPU 缓存（L1/L2/L3）命中率下降</li><li>需要重新建立虚拟地址到物理地址的映射</li></ul><hr><h3 id="q296-进程间通信方式有哪些" tabindex="-1">Q296: 进程间通信方式有哪些？ <a class="header-anchor" href="#q296-进程间通信方式有哪些" aria-label="Permalink to &quot;Q296: 进程间通信方式有哪些？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥 高频</p><p><strong>考点</strong>：管道、消息队列、共享内存、信号、Socket</p><p><strong>💡 记忆关键词</strong>：管道消息、共享内存、信号Socket</p><p><strong>答案要点</strong>：</p><ul><li><strong>管道</strong>（Pipe）：匿名（父子进程）、命名（FIFO）</li><li><strong>消息队列</strong>：System V / POSIX，消息队列传递</li><li><strong>共享内存</strong>：最快，直接映射同一物理内存</li><li><strong>信号</strong>（Signal）：异步通知，如 SIGKILL、SIGTERM</li><li><strong>Socket</strong>：跨机器通信，最通用</li></ul><hr><h3 id="q297-进程间同步的方式有哪些" tabindex="-1">Q297: 进程间同步的方式有哪些？ <a class="header-anchor" href="#q297-进程间同步的方式有哪些" aria-label="Permalink to &quot;Q297: 进程间同步的方式有哪些？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：信号量、互斥锁、条件变量、文件锁</p><p><strong>💡 记忆关键词</strong>：信号量计数、互斥锁保护、条件变量等待</p><p><strong>答案要点</strong>：</p><ul><li><strong>信号量</strong>（Semaphore）：计数器，控制资源访问</li><li><strong>互斥锁</strong>（Mutex）：临界区保护</li><li><strong>条件变量</strong>（Cond）：等待条件成立</li><li><strong>文件锁</strong>：flock、fcntl</li><li><strong>屏障</strong>（Barrier）：多线程同步点</li></ul><hr><h3 id="q298-线程同步的方式有哪些" tabindex="-1">Q298: 线程同步的方式有哪些？ <a class="header-anchor" href="#q298-线程同步的方式有哪些" aria-label="Permalink to &quot;Q298: 线程同步的方式有哪些？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：Mutex、Cond、Semaphore、Atomic</p><p><strong>💡 记忆关键词</strong>：互斥读写、条件等待、原子无锁</p><p><strong>答案要点</strong>：</p><ul><li><strong>互斥锁</strong>（Mutex）：互斥访问共享资源</li><li><strong>读写锁</strong>（RWMutex）：多读单写</li><li><strong>条件变量</strong>（Cond）：等待/通知</li><li><strong>信号量</strong>（Semaphore）：资源计数</li><li><strong>原子操作</strong>（Atomic）：无锁同步</li><li><strong>Barrier</strong>：等待所有线程到达</li></ul><hr><h3 id="q299-线程的分类" tabindex="-1">Q299: 线程的分类？ <a class="header-anchor" href="#q299-线程的分类" aria-label="Permalink to &quot;Q299: 线程的分类？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：用户级、内核级、混合</p><p><strong>💡 记忆关键词</strong>：用户线程、内核线程、M:N映射</p><p><strong>答案要点</strong>：</p><ul><li><strong>用户级线程</strong>：用户态管理，OS 不可见（如早期 Go）</li><li><strong>内核级线程</strong>：OS 内核管理，完全调度</li><li><strong>混合线程</strong>：用户态+内核态映射（如 Go GMP 模型）</li><li>N:1（多用户线程映射到一线程）、1:1、M:N</li></ul><hr><h3 id="q300-什么是临界区-如何解决冲突" tabindex="-1">Q300: 什么是临界区，如何解决冲突？ <a class="header-anchor" href="#q300-什么是临界区-如何解决冲突" aria-label="Permalink to &quot;Q300: 什么是临界区，如何解决冲突？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：共享资源、互斥访问、同步机制</p><p><strong>💡 记忆关键词</strong>：共享代码段、互斥访问、同步保护</p><p><strong>答案要点</strong>：</p><ul><li>临界区：访问共享资源的代码段</li><li>解决冲突： <ol><li>互斥锁（Mutex）</li><li>信号量（Semaphore）</li><li>原子操作（Atomic）</li><li>关闭中断（内核态）</li></ol></li></ul><hr><h3 id="q301-什么是死锁-死锁产生的条件" tabindex="-1">Q301: 什么是死锁？死锁产生的条件？ <a class="header-anchor" href="#q301-什么是死锁-死锁产生的条件" aria-label="Permalink to &quot;Q301: 什么是死锁？死锁产生的条件？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥 高频</p><p><strong>考点</strong>：四个必要条件、预防、避免、检测</p><p><strong>💡 记忆关键词</strong>：互斥占有、不可抢占、循环等待</p><p><strong>答案要点</strong>：</p><ul><li>死锁：多个进程/线程相互等待对方释放资源，永久阻塞</li><li><strong>四个必要条件</strong>： <ol><li>互斥条件</li><li>占有并等待</li><li>不可抢占</li><li>循环等待</li></ol></li><li><strong>预防</strong>：破坏任一条件</li><li><strong>避免</strong>：银行家算法</li><li><strong>检测与恢复</strong>：资源分配图</li></ul><hr><h3 id="q302-进程调度策略有哪几种" tabindex="-1">Q302: 进程调度策略有哪几种？ <a class="header-anchor" href="#q302-进程调度策略有哪几种" aria-label="Permalink to &quot;Q302: 进程调度策略有哪几种？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：FCFS、SJF、优先级、时间片轮转</p><p><strong>💡 记忆关键词</strong>：先来先服、短作业优、时间片轮转</p><p><strong>答案要点</strong>：</p><ul><li><strong>FCFS</strong>（先来先服务）：简单，但短作业等待长</li><li><strong>SJF</strong>（短作业优先）：平均等待时间最短</li><li><strong>优先级调度</strong>：按优先级执行</li><li><strong>时间片轮转</strong>（RR）：每个进程分配固定时间片</li><li><strong>多级反馈队列</strong>：综合策略，Linux CFS 使用</li></ul><hr><h3 id="q303-进程有哪些状态" tabindex="-1">Q303: 进程有哪些状态？ <a class="header-anchor" href="#q303-进程有哪些状态" aria-label="Permalink to &quot;Q303: 进程有哪些状态？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：五状态模型、转换</p><p><strong>💡 记忆关键词</strong>：创建就绪、运行阻塞、终止五态</p><p><strong>答案要点</strong>：</p><ul><li><strong>创建</strong>（New）</li><li><strong>就绪</strong>（Ready）：等待 CPU</li><li><strong>运行</strong>（Running）：正在执行</li><li><strong>阻塞</strong>（Blocked/Waiting）：等待事件</li><li><strong>终止</strong>（Terminated）</li></ul>',91)),(o(),i(a,null,{default:r(()=>[g(l,{id:"mermaid-570",class:"mermaid",graph:"stateDiagram-v2%0A%20%20%20%20%5B*%5D%20--%3E%20New%3A%20%E5%88%9B%E5%BB%BA%E8%BF%9B%E7%A8%8B%0A%20%20%20%20New%20--%3E%20Ready%3A%20%E8%B5%84%E6%BA%90%E5%88%86%E9%85%8D%E5%AE%8C%E6%88%90%0A%20%20%20%20Ready%20--%3E%20Running%3A%20%E8%B0%83%E5%BA%A6%E5%99%A8%E9%80%89%E4%B8%AD%0A%20%20%20%20Running%20--%3E%20Ready%3A%20%E6%97%B6%E9%97%B4%E7%89%87%E7%94%A8%E5%AE%8C%0A%20%20%20%20Running%20--%3E%20Blocked%3A%20%E7%AD%89%E5%BE%85IO%2F%E4%BA%8B%E4%BB%B6%0A%20%20%20%20Blocked%20--%3E%20Ready%3A%20%E4%BA%8B%E4%BB%B6%E5%AE%8C%E6%88%90%2FIO%E5%B0%B1%E7%BB%AA%0A%20%20%20%20Running%20--%3E%20Terminated%3A%20%E6%89%A7%E8%A1%8C%E5%AE%8C%E6%AF%95%2F%E8%A2%AB%E7%BB%88%E6%AD%A2%0A%20%20%20%20Terminated%20--%3E%20%5B*%5D%0A%20%20%20%20%0A%20%20%20%20classDef%20readyState%20fill%3A%23e8f5e9%0A%20%20%20%20classDef%20runningState%20fill%3A%23fff3e0%0A%20%20%20%20classDef%20blockedState%20fill%3A%23ffebee%0A%20%20%20%20class%20Ready%20readyState%0A%20%20%20%20class%20Running%20runningState%0A%20%20%20%20class%20Blocked%20blockedState%0A"})]),fallback:r(()=>[...t[0]||(t[0]=[n(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=s('<p><strong>📝 一句话总结</strong>：创建就绪运行中，阻塞等待事件完；终止结束五状态，转换流程记心间。</p><hr><h3 id="q304-什么是分页" tabindex="-1">Q304: 什么是分页？ <a class="header-anchor" href="#q304-什么是分页" aria-label="Permalink to &quot;Q304: 什么是分页？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：页框、页表、虚拟地址</p><p><strong>💡 记忆关键词</strong>：固定大小、页表映射、虚拟内存</p><p><strong>答案要点</strong>：</p><ul><li>将物理内存和虚拟内存划分为固定大小的块（页）</li><li>页大小通常 4KB</li><li>通过页表映射虚拟页到物理页框</li><li>优点：无外部碎片，支持虚拟内存</li></ul><hr><h3 id="q305-什么是分段" tabindex="-1">Q305: 什么是分段？ <a class="header-anchor" href="#q305-什么是分段" aria-label="Permalink to &quot;Q305: 什么是分段？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：段表、逻辑段、可变大小</p><p><strong>💡 记忆关键词</strong>：逻辑分段、可变大小、段表映射</p><p><strong>答案要点</strong>：</p><ul><li>将程序划分为逻辑段（代码段、数据段、堆栈段）</li><li>段大小可变</li><li>通过段表映射逻辑地址到物理地址</li><li>优点：符合程序逻辑结构，支持共享和保护</li></ul><hr><h3 id="q306-分页和分段有什么区别" tabindex="-1">Q306: 分页和分段有什么区别？ <a class="header-anchor" href="#q306-分页和分段有什么区别" aria-label="Permalink to &quot;Q306: 分页和分段有什么区别？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：大小、碎片、共享</p><p><strong>💡 记忆关键词</strong>：固定可变、内外碎片、页段共享</p><p><strong>答案要点</strong>：</p><table tabindex="0"><thead><tr><th>维度</th><th>分页</th><th>分段</th></tr></thead><tbody><tr><td>大小</td><td>固定</td><td>可变</td></tr><tr><td>碎片</td><td>内部碎片</td><td>外部碎片</td></tr><tr><td>可见性</td><td>对用户透明</td><td>用户可见</td></tr><tr><td>共享</td><td>页级共享</td><td>段级共享（更自然）</td></tr><tr><td>保护</td><td>页级</td><td>段级</td></tr></tbody></table><p><strong>📝 一句话总结</strong>：分页固定内碎片，分段可变外碎片；分页透明分段显，共享保护各不同。</p><hr><h3 id="q307-什么是交换空间-swap" tabindex="-1">Q307: 什么是交换空间（Swap）？ <a class="header-anchor" href="#q307-什么是交换空间-swap" aria-label="Permalink to &quot;Q307: 什么是交换空间（Swap）？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：虚拟内存扩展、页面换出、性能</p><p><strong>💡 记忆关键词</strong>：磁盘扩展、页面换出、性能下降</p><p><strong>答案要点</strong>：</p><ul><li>Swap 是磁盘上的虚拟内存扩展</li><li>物理内存不足时，将不活跃页面换出到 Swap</li><li>换入换出导致性能大幅下降</li><li>设置：<code>swapon</code>、<code>swapoff</code>、<code>/etc/fstab</code></li></ul><hr><h3 id="q308-页面替换算法有哪些" tabindex="-1">Q308: 页面替换算法有哪些？ <a class="header-anchor" href="#q308-页面替换算法有哪些" aria-label="Permalink to &quot;Q308: 页面替换算法有哪些？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：OPT、FIFO、LRU、Clock</p><p><strong>💡 记忆关键词</strong>：OPT最优、LRU常用、Clock近似</p><p><strong>答案要点</strong>：</p><ul><li><strong>OPT</strong>（最优）：替换最久后才使用的页面（理论）</li><li><strong>FIFO</strong>：先进先出，可能 Belady 异常</li><li><strong>LRU</strong>：替换最近最少使用的页面（常用）</li><li><strong>Clock</strong>：近似 LRU，实现简单</li><li><strong>LFU</strong>：替换使用频率最低的页面</li></ul><hr><h3 id="q309-什么是缓冲区溢出-有什么危害" tabindex="-1">Q309: 什么是缓冲区溢出？有什么危害？ <a class="header-anchor" href="#q309-什么是缓冲区溢出-有什么危害" aria-label="Permalink to &quot;Q309: 什么是缓冲区溢出？有什么危害？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：栈溢出、代码注入、安全防护</p><p><strong>💡 记忆关键词</strong>：超出容量、覆盖返回、代码注入</p><p><strong>答案要点</strong>：</p><ul><li>向缓冲区写入超出其容量的数据</li><li>覆盖相邻内存，可能覆盖返回地址</li><li>危害：程序崩溃、代码注入、权限提升</li><li>防护：栈保护（Canary）、DEP、ASLR、边界检查</li></ul><hr><h3 id="q310-什么是虚拟内存" tabindex="-1">Q310: 什么是虚拟内存？ <a class="header-anchor" href="#q310-什么是虚拟内存" aria-label="Permalink to &quot;Q310: 什么是虚拟内存？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：地址空间、按需分页、隔离</p><p><strong>💡 记忆关键词</strong>：独立地址、按需分页、进程隔离</p><p><strong>答案要点</strong>：</p><ul><li>为每个进程提供独立的地址空间</li><li>按需加载页面到物理内存</li><li>允许程序使用比物理内存更大的地址空间</li><li>提供进程间内存隔离</li></ul><hr><h3 id="q311-讲一讲-io-多路复用" tabindex="-1">Q311: 讲一讲 IO 多路复用？ <a class="header-anchor" href="#q311-讲一讲-io-多路复用" aria-label="Permalink to &quot;Q311: 讲一讲 IO 多路复用？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥 高频</p><p><strong>考点</strong>：select、poll、epoll、高并发</p><p><strong>💡 记忆关键词</strong>：单线程监控、epoll最优、事件驱动</p><p><strong>答案要点</strong>：</p><ul><li>允许单个线程监控多个文件描述符</li><li><strong>select</strong>：FD 数量有限（1024），每次全量拷贝</li><li><strong>poll</strong>：无 FD 数量限制，仍全量拷贝</li><li><strong>epoll</strong>（Linux）：事件驱动，仅返回就绪 FD，性能最优</li><li>Go 的 net 包底层使用 epoll/kqueue</li></ul><hr><h3 id="q312-硬链接和软链接有什么区别" tabindex="-1">Q312: 硬链接和软链接有什么区别？ <a class="header-anchor" href="#q312-硬链接和软链接有什么区别" aria-label="Permalink to &quot;Q312: 硬链接和软链接有什么区别？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：inode、跨文件系统、删除影响</p><p><strong>💡 记忆关键词</strong>：同inode、跨文件系统、源删影响</p><p><strong>答案要点</strong>：</p><table tabindex="0"><thead><tr><th>维度</th><th>硬链接</th><th>软链接</th></tr></thead><tbody><tr><td>inode</td><td>相同</td><td>不同</td></tr><tr><td>跨文件系统</td><td>不支持</td><td>支持</td></tr><tr><td>目录</td><td>不支持</td><td>支持</td></tr><tr><td>源文件删除</td><td>仍可访问</td><td>失效（悬空）</td></tr><tr><td>本质</td><td>同一文件多个名字</td><td>指向路径的快捷方式</td></tr></tbody></table><p><strong>📝 一句话总结</strong>：硬链同 inode 不跨系，软链不同 inode 跨；源删硬链仍可访，软链失效悬空路。</p><hr><h3 id="q313-中断的处理过程" tabindex="-1">Q313: 中断的处理过程？ <a class="header-anchor" href="#q313-中断的处理过程" aria-label="Permalink to &quot;Q313: 中断的处理过程？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：保存上下文、中断服务程序、恢复</p><p><strong>💡 记忆关键词</strong>：保存上下文、查向量表、执行ISR</p><p><strong>答案要点</strong>：</p><ol><li>CPU 暂停当前执行</li><li>保存上下文（寄存器、FLAGS、返回地址）</li><li>根据中断号查找中断向量表</li><li>执行中断服务程序（ISR）</li><li>恢复上下文，返回原程序</li></ol><hr><h3 id="q314-中断和轮询有什么区别" tabindex="-1">Q314: 中断和轮询有什么区别？ <a class="header-anchor" href="#q314-中断和轮询有什么区别" aria-label="Permalink to &quot;Q314: 中断和轮询有什么区别？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：主动 vs 被动、CPU 利用率、实时性</p><p><strong>💡 记忆关键词</strong>：设备主动、CPU定期检查、epoll结合</p><p><strong>答案要点</strong>：</p><ul><li><strong>中断</strong>：设备主动通知 CPU，CPU 利用率高，实时性好</li><li><strong>轮询</strong>：CPU 定期检查设备状态，浪费 CPU，延迟不确定</li><li>现代系统以中断为主，epoll 结合两者优势</li></ul><hr><h3 id="q315-请详细介绍-tcp-的三次握手机制-为什么要三次握手" tabindex="-1">Q315: 请详细介绍 TCP 的三次握手机制，为什么要三次握手？ <a class="header-anchor" href="#q315-请详细介绍-tcp-的三次握手机制-为什么要三次握手" aria-label="Permalink to &quot;Q315: 请详细介绍 TCP 的三次握手机制，为什么要三次握手？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥 高频</p><p><strong>考点</strong>：SYN、SYN-ACK、ACK、连接建立</p><p><strong>💡 记忆关键词</strong>：SYN同步、收发确认、序列号同步</p><p><strong>答案要点</strong>：</p><ol><li>Client → Server：SYN（seq=x）</li><li>Server → Client：SYN-ACK（seq=y, ack=x+1）</li><li>Client → Server：ACK（ack=y+1）</li></ol><ul><li><strong>为什么三次</strong>： <ol><li>防止已失效的连接请求突然到达</li><li>双方确认对方的收发能力</li><li>同步初始序列号</li></ol></li></ul>',88)),(o(),i(a,null,{default:r(()=>[g(l,{id:"mermaid-1165",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20C%20as%20Client%0A%20%20%20%20participant%20S%20as%20Server%0A%20%20%20%20%0A%20%20%20%20Note%20over%20C%2CS%3A%20%E7%AC%AC%E4%B8%80%E6%AC%A1%E6%8F%A1%E6%89%8B%0A%20%20%20%20C-%3E%3ES%3A%20SYN%20(seq%3Dx)%0A%20%20%20%20Note%20right%20of%20C%3A%20%E8%BF%9B%E5%85%A5%20SYN_SENT%20%E7%8A%B6%E6%80%81%0A%20%20%20%20%0A%20%20%20%20Note%20over%20C%2CS%3A%20%E7%AC%AC%E4%BA%8C%E6%AC%A1%E6%8F%A1%E6%89%8B%0A%20%20%20%20S-%3E%3EC%3A%20SYN-ACK%20(seq%3Dy%2C%20ack%3Dx%2B1)%0A%20%20%20%20Note%20right%20of%20S%3A%20%E8%BF%9B%E5%85%A5%20SYN_RCVD%20%E7%8A%B6%E6%80%81%0A%20%20%20%20%0A%20%20%20%20Note%20over%20C%2CS%3A%20%E7%AC%AC%E4%B8%89%E6%AC%A1%E6%8F%A1%E6%89%8B%0A%20%20%20%20C-%3E%3ES%3A%20ACK%20(ack%3Dy%2B1)%0A%20%20%20%20Note%20right%20of%20C%3A%20%E8%BF%9B%E5%85%A5%20ESTABLISHED%20%E7%8A%B6%E6%80%81%0A%20%20%20%20Note%20right%20of%20S%3A%20%E6%94%B6%E5%88%B0ACK%E5%90%8E%E8%BF%9B%E5%85%A5%20ESTABLISHED%20%E7%8A%B6%E6%80%81%0A"})]),fallback:r(()=>[...t[1]||(t[1]=[n(" Loading... ",-1)])]),_:1})),t[5]||(t[5]=s('<p><strong>📝 一句话总结</strong>：三次握手 SYN 始，SYN-ACK 回 ACK 终；防失效确认收发，同步序列建连接。</p><hr><h3 id="q316-讲一讲-syn-超时、洪泛攻击-以及解决策略" tabindex="-1">Q316: 讲一讲 SYN 超时、洪泛攻击，以及解决策略 <a class="header-anchor" href="#q316-讲一讲-syn-超时、洪泛攻击-以及解决策略" aria-label="Permalink to &quot;Q316: 讲一讲 SYN 超时、洪泛攻击，以及解决策略&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：半连接队列、SYN Cookie、防火墙</p><p><strong>💡 记忆关键词</strong>：半连接队列、SYN Cookie、防火墙过滤</p><p><strong>答案要点</strong>：</p><ul><li><strong>SYN 超时</strong>：Server 发送 SYN-ACK 后等待 ACK 超时（默认 60s）</li><li><strong>SYN Flood 攻击</strong>：伪造大量 SYN 请求，耗尽半连接队列</li><li><strong>解决</strong>： <ol><li>SYN Cookie：无状态验证</li><li>增加半连接队列大小</li><li>减少 SYN-ACK 重试次数</li><li>防火墙/IPS 过滤</li></ol></li></ul><hr><h3 id="q317-详细介绍-tcp-的四次挥手机制-为什么要有-time-wait-状态" tabindex="-1">Q317: 详细介绍 TCP 的四次挥手机制，为什么要有 TIME_WAIT 状态？ <a class="header-anchor" href="#q317-详细介绍-tcp-的四次挥手机制-为什么要有-time-wait-状态" aria-label="Permalink to &quot;Q317: 详细介绍 TCP 的四次挥手机制，为什么要有 TIME_WAIT 状态？&quot;">​</a></h3><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥 高频</p><p><strong>考点</strong>：FIN、ACK、CLOSE_WAIT、TIME_WAIT</p><p><strong>💡 记忆关键词</strong>：FIN关闭、TIME_WAIT等待、2MSL消散</p><p><strong>答案要点</strong>：</p><ol><li>A → B：FIN（A 无数据发送）</li><li>B → A：ACK（确认收到 FIN）</li><li>B → A：FIN（B 也无数据发送）</li><li>A → B：ACK（确认收到 FIN）</li></ol><ul><li><strong>TIME_WAIT 作用</strong>： <ol><li>确保最后一个 ACK 到达 B</li><li>让旧连接的数据包在网络中消散（2MSL）</li></ol></li><li><strong>大量 CLOSE_WAIT</strong>：应用层未调用 close()，检查代码</li></ul>',16)),(o(),i(a,null,{default:r(()=>[g(l,{id:"mermaid-1286",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20A%20as%20Client%20(%E4%B8%BB%E5%8A%A8%E5%85%B3%E9%97%AD)%0A%20%20%20%20participant%20B%20as%20Server%20(%E8%A2%AB%E5%8A%A8%E5%85%B3%E9%97%AD)%0A%20%20%20%20%0A%20%20%20%20Note%20over%20A%2CB%3A%20%E7%AC%AC%E4%B8%80%E6%AC%A1%E6%8C%A5%E6%89%8B%0A%20%20%20%20A-%3E%3EB%3A%20FIN%0A%20%20%20%20Note%20right%20of%20A%3A%20%E8%BF%9B%E5%85%A5%20FIN_WAIT_1%0A%20%20%20%20%0A%20%20%20%20Note%20over%20A%2CB%3A%20%E7%AC%AC%E4%BA%8C%E6%AC%A1%E6%8C%A5%E6%89%8B%0A%20%20%20%20B-%3E%3EA%3A%20ACK%0A%20%20%20%20Note%20right%20of%20B%3A%20%E8%BF%9B%E5%85%A5%20CLOSE_WAIT%0A%20%20%20%20Note%20right%20of%20A%3A%20%E8%BF%9B%E5%85%A5%20FIN_WAIT_2%0A%20%20%20%20%0A%20%20%20%20Note%20over%20A%2CB%3A%20%E7%AC%AC%E4%B8%89%E6%AC%A1%E6%8C%A5%E6%89%8B%20(B%E6%95%B0%E6%8D%AE%E5%8F%91%E9%80%81%E5%AE%8C%E6%AF%95)%0A%20%20%20%20B-%3E%3EA%3A%20FIN%0A%20%20%20%20Note%20right%20of%20B%3A%20%E8%BF%9B%E5%85%A5%20LAST_ACK%0A%20%20%20%20%0A%20%20%20%20Note%20over%20A%2CB%3A%20%E7%AC%AC%E5%9B%9B%E6%AC%A1%E6%8C%A5%E6%89%8B%0A%20%20%20%20A-%3E%3EB%3A%20ACK%0A%20%20%20%20Note%20right%20of%20A%3A%20%E8%BF%9B%E5%85%A5%20TIME_WAIT%20(%E7%AD%89%E5%BE%852MSL)%0A%20%20%20%20Note%20right%20of%20B%3A%20%E6%94%B6%E5%88%B0ACK%E5%90%8E%E8%BF%9B%E5%85%A5%20CLOSED%0A%20%20%20%20%0A%20%20%20%20Note%20right%20of%20A%3A%202MSL%E5%90%8E%E8%BF%9B%E5%85%A5%20CLOSED%0A"})]),fallback:r(()=>[...t[2]||(t[2]=[n(" Loading... ",-1)])]),_:1})),t[6]||(t[6]=e("p",null,[e("strong",null,"📝 一句话总结"),n("：四次挥手 FIN 始，ACK 确认 FIN 再 ACK 终；TIME_WAIT 等 2MSL，旧包消散连接清。")],-1)),t[7]||(t[7]=e("hr",null,null,-1))])}const f=p(h,[["render",E]]);export{b as __pageData,f as default};
